# governance.tf — RBAC + Policy assignments at management group scope

variable "corp_mg_id"        { type = string }
variable "sandbox_sub_id"    { type = string }
variable "platform_ops_gid"  { type = string }  # Entra group object ID
variable "security_gid"      { type = string }
variable "law_workspace_id"  { type = string }

# ── RBAC Layer ─────────────────────────────────────────────────────────
# Platform Ops: Reader across entire Corp MG (read-only observability)
resource "azurerm_role_assignment" "platform_reader" {
  scope                = var.corp_mg_id
  role_definition_name = "Reader"
  principal_id         = var.platform_ops_gid
}

# Security team: Security Reader at Corp MG
resource "azurerm_role_assignment" "security_reader" {
  scope                = var.corp_mg_id
  role_definition_name = "Security Reader"
  principal_id         = var.security_gid
}

# ── Policy Layer ────────────────────────────────────────────────────────
# These apply to ALL identities in the Corp MG — even Owners in child subs

# Require cost-center tag
resource "azurerm_management_group_policy_assignment" "require_cost_center_tag" {
  name                 = "require-cost-center-tag"
  display_name         = "Require cost-center tag on all resources"
  policy_definition_id = data.azurerm_policy_definition.require_tag.id
  management_group_id  = var.corp_mg_id
  parameters = jsonencode({ tagName = { value = "cost-center" } })
}

# Allowed regions
resource "azurerm_management_group_policy_assignment" "allowed_locations" {
  name                 = "allowed-locations"
  display_name         = "Restrict resources to approved regions"
  policy_definition_id = "/providers/Microsoft.Authorization/policyDefinitions/e56962a6-4747-49cd-b67b-bf8b01975c4f"
  management_group_id  = var.corp_mg_id
  parameters = jsonencode({
    listOfAllowedLocations = { value = ["eastus2", "westus2", "northeurope"] }
  })
  not_scopes = [
    # Sandbox is excluded from location enforcement — allow any region for testing
    "/subscriptions/${var.sandbox_sub_id}"
  ]
}

# Deny public storage accounts — applies even to Owners
resource "azurerm_management_group_policy_assignment" "deny_public_storage" {
  name                 = "deny-public-storage"
  display_name         = "Deny public blob access on storage accounts"
  policy_definition_id = data.azurerm_policy_definition.deny_public_blob.id
  management_group_id  = var.corp_mg_id
}

# DINE: Deploy Log Analytics agent to VMs (requires managed identity + RBAC)
resource "azurerm_management_group_policy_assignment" "deploy_law_agent" {
  name                 = "deploy-law-agent"
  display_name         = "Deploy Log Analytics agent to VMs"
  policy_definition_id = data.azurerm_policy_definition.deploy_law.id
  management_group_id  = var.corp_mg_id
  identity { type = "SystemAssigned" }
  location = "eastus2"
  parameters = jsonencode({
    logAnalyticsWorkspaceId = { value = var.law_workspace_id }
  })
}

# Grant the DINE policy managed identity Contributor (needed to deploy VM extensions)
resource "azurerm_role_assignment" "policy_dine_identity" {
  scope                = var.corp_mg_id
  role_definition_name = "Contributor"
  principal_id         = azurerm_management_group_policy_assignment.deploy_law_agent.identity[0].principal_id
  depends_on           = [azurerm_management_group_policy_assignment.deploy_law_agent]
}

data "azurerm_policy_definition" "require_tag" {
  display_name = "Require a tag on resources"
}
data "azurerm_policy_definition" "deny_public_blob" {
  display_name = "Storage accounts should prevent shared key access"
}
data "azurerm_policy_definition" "deploy_law" {
  display_name = "Deploy Log Analytics agent for Windows VMs"
}
